const input = $input.first().json;
const headers = input.headers || {};
const body = input.body || input;

const tenantId = (headers['x-tenant-id'] || headers['X-Tenant-ID'] || '').trim();
const apiKey = (headers['x-api-key'] || headers['X-API-Key'] || '').trim();

const content = (body.content || body.text || '').trim();
const name = (body.name || 'Unbenanntes Dokument').trim();
const sourceType = (body.source_type || 'manual').trim();
const s3Key = body.s3_key || null;
const s3Bucket = body.s3_bucket || null;
const metadata = body.metadata || {};

if (!tenantId) throw new Error('X-Tenant-ID Header fehlt');
if (!apiKey) throw new Error('X-API-Key Header fehlt');
if (!content || content.length < 10) throw new Error('content/text Feld fehlt oder zu kurz (min. 10 Zeichen)');
if (!['manual', 'file', 'url', 'pdf'].includes(sourceType)) throw new Error('source_type muss manual/file/url/pdf sein');

return [{ json: { tenantId, apiKey, content, name, sourceType, s3Key, s3Bucket, metadata, startedAt: Date.now() } }];

// Text in Chunks aufteilen (2000 Zeichen, 200 Overlap)
const CHUNK_SIZE = 2000;
const OVERLAP = 200;

const pgResult = $input.first().json;
const inputData = $('Input validieren').first().json;
const tenantAuth = $('PG: Tenant Auth').first().json;

const sourceId = pgResult.source_id;
const documentId = pgResult.document_id;
const tenantId = inputData.tenantId;
const text = inputData.content.replace(/\r\n/g, '\n').replace(/\n{3,}/g, '\n\n').trim();

if (!sourceId || !documentId) {
  throw new Error('Source/Document konnte nicht angelegt werden: ' + JSON.stringify(pgResult));
}

// Chunking
const chunks = [];
let start = 0;
let idx = 0;
while (start < text.length) {
  let end = Math.min(start + CHUNK_SIZE, text.length);
  if (end < text.length) {
    const lastNl = text.lastIndexOf('\n', end);
    const lastDot = text.lastIndexOf('.', end);
    const boundary = Math.max(lastNl, lastDot);
    if (boundary > start + CHUNK_SIZE * 0.5) end = boundary + 1;
  }
  const chunk = text.substring(start, end).trim();
  if (chunk.length >= 20) {
    chunks.push({
      chunkIndex: idx,
      content: chunk,
      tokenCount: Math.ceil(chunk.length / 4),
      documentId,
      sourceId,
      tenantId
    });
    idx++;
  }
  start = end - OVERLAP;
  if (start >= text.length) break;
}

if (chunks.length === 0) throw new Error('Keine Chunks erzeugt — Text zu kurz?');

return chunks.map(c => ({ json: c }));

const embedResult = $input.first().json;
const chunkData = $('Text chunken').item.json;

const embeddingArray = embedResult.embeddings?.[0] || embedResult.embedding || [];

if (!Array.isArray(embeddingArray) || embeddingArray.length !== 1024) {
  throw new Error(`Embedding-Fehler: ${embeddingArray.length} Dimensionen (erwartet 1024)`);
}

const vectorStr = '[' + embeddingArray.map(v => v.toFixed(8)).join(',') + ']';

return [{ json: {
  ...chunkData,
  vectorStr
}}];

// Alle Chunks sammeln und Status aktualisieren
const allItems = $input.all();
const chunkIds = allItems.map(i => i.json.chunk_id).filter(Boolean);
const inputData = $('Input validieren').first().json;
const pgResult = $('PG: Source + Document anlegen').first().json;

return [{ json: {
  sourceId: pgResult.source_id,
  documentId: pgResult.document_id,
  tenantId: inputData.tenantId,
  chunksCreated: chunkIds.length,
  chunkIds
}}];

